15: namespace Envoy {
16: namespace Extensions {
17: namespace HttpFilters {
18: namespace BufferFilter {
19: 
20: BufferFilterSettings::BufferFilterSettings(
21:     const envoy::extensions::filters::http::buffer::v3::Buffer& proto_config)
22:     : disabled_(false),
23:       max_request_bytes_(static_cast<uint64_t>(proto_config.max_request_bytes().value())) {}
24: 
25: BufferFilterSettings::BufferFilterSettings(
26:     const envoy::extensions::filters::http::buffer::v3::BufferPerRoute& proto_config)
27:     : disabled_(proto_config.disabled()),
28:       max_request_bytes_(
29:           proto_config.has_buffer()
30:               ? static_cast<uint64_t>(proto_config.buffer().max_request_bytes().value())
31:               : 0) {}
32: 
33: BufferFilterConfig::BufferFilterConfig(
34:     const envoy::extensions::filters::http::buffer::v3::Buffer& proto_config)
35:     : settings_(proto_config) {}
36: 
37: BufferFilter::BufferFilter(BufferFilterConfigSharedPtr config)
38:     : config_(config), settings_(config->settings()) {}
39: 
40: void BufferFilter::initConfig() {
41:   ASSERT(!config_initialized_);
42:   config_initialized_ = true;
43:   settings_ = config_->settings();
44: 
45:   const auto* route_local =
46:       Http::Utility::resolveMostSpecificPerFilterConfig<BufferFilterSettings>(callbacks_);
47:   settings_ = route_local ? route_local : settings_;
48: }
49: 
50: Http::FilterHeadersStatus BufferFilter::decodeHeaders(Http::RequestHeaderMap& headers,
51:                                                       bool end_stream) {
52:   if (end_stream) {
53:     // If this is a header-only request, we don't need to do any buffering.
54:     return Http::FilterHeadersStatus::Continue;
55:   }
56: 
57:   initConfig();
58:   if (settings_->disabled()) {
59:     // The filter has been disabled for this route.
60:     return Http::FilterHeadersStatus::Continue;
61:   }
62: 
63:   callbacks_->setDecoderBufferLimit(settings_->maxRequestBytes());
64:   request_headers_ = &headers;
65: 
66:   return Http::FilterHeadersStatus::StopIteration;
67: }
68: 
69: Http::FilterDataStatus BufferFilter::decodeData(Buffer::Instance& data, bool end_stream) {
70:   content_length_ += data.length();
71:   if (end_stream || settings_->disabled()) {
72:     maybeAddContentLength();
73: 
74:     return Http::FilterDataStatus::Continue;
75:   }
76: 
77:   // Buffer until the complete request has been processed or the ConnectionManagerImpl sends a 413.
78:   return Http::FilterDataStatus::StopIterationAndBuffer;
79: }
80: 
81: Http::FilterTrailersStatus BufferFilter::decodeTrailers(Http::RequestTrailerMap&) {
82:   maybeAddContentLength();
83: 
84:   return Http::FilterTrailersStatus::Continue;
85: }
86: 
87: void BufferFilter::setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) {
88:   callbacks_ = &callbacks;
89: }
90: 
91: void BufferFilter::maybeAddContentLength() {
92:   // request_headers_ is initialized iff plugin is enabled.
93:   if (request_headers_ != nullptr && request_headers_->ContentLength() == nullptr) {
94:     ASSERT(!settings_->disabled());
95:     request_headers_->setContentLength(content_length_);
96:   }
97: }
98: 
99: } // namespace BufferFilter
100: } // namespace HttpFilters
101: } // namespace Extensions
102: } // namespace Envoy
