19: public:
20:   const char* prefix() const { return ThreadSafeSingleton<Http::PrefixValue>::get().prefix(); }
21: 
22:   const Http::LowerCaseString KillRequest{absl::StrCat(prefix(), "-kill-request")};
23: };
