27: /**
28:  * A filter that will crash Envoy if IsKillRequestEnabled() return true and
29:  * incoming request contains HTTP KillRequest header with values in
30:  * one of (case-insensitive) ["true", "t", "yes", "y", "1"].
31:  */
32: class KillRequestFilter : public Http::StreamFilter, Logger::Loggable<Logger::Id::filter> {
33: public:
34:   KillRequestFilter(
35:       const envoy::extensions::filters::http::kill_request::v3::KillRequest& kill_request,
36:       Random::RandomGenerator& random_generator)
37:       : kill_request_(kill_request), random_generator_(random_generator) {}
38: 
39:   ~KillRequestFilter() override = default;
40: 
41:   // Http::StreamFilterBase
42:   void onDestroy() override {}
43: 
44:   // Http::StreamDecoderFilter
45:   Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
46:                                           bool end_stream) override;
47: 
48:   Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
49:     return Http::FilterDataStatus::Continue;
50:   }
51: 
52:   Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
53:     return Http::FilterTrailersStatus::Continue;
54:   }
55: 
56:   void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
57:     decoder_callbacks_ = &callbacks;
58:   }
59: 
60:   // Http::StreamEncoderFilter
61:   Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
62:     return Http::Filter1xxHeadersStatus::Continue;
63:   }
64: 
65:   Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
66: 
67:   Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
68:     return Http::FilterDataStatus::Continue;
69:   }
70: 
71:   Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
72:     return Http::FilterTrailersStatus::Continue;
73:   }
74: 
75:   Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
76:     return Http::FilterMetadataStatus::Continue;
77:   }
78: 
79:   void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks&) override {}
80: 
81: private:
82:   // Return a random boolean value, with probability configured in KillRequest
83:   // equaling true.
84:   bool isKillRequestEnabled();
85:   bool isKillRequest(Http::HeaderMap& map);
86: 
87:   envoy::extensions::filters::http::kill_request::v3::KillRequest kill_request_;
88:   Random::RandomGenerator& random_generator_;
89:   Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
90: };
