12: namespace Envoy {
13: namespace Extensions {
14: namespace HttpFilters {
15: namespace KillRequest {
16: 
17: using ::envoy::extensions::filters::http::kill_request::v3::KillRequest;
18: 
19: KillSettings::KillSettings(const KillRequest& kill_request)
20:     : kill_probability_(kill_request.probability()), direction_(kill_request.direction()) {}
21: 
22: bool KillRequestFilter::isKillRequestEnabled() {
23:   return ProtobufPercentHelper::evaluateFractionalPercent(kill_request_.probability(),
24:                                                           random_generator_.random());
25: }
26: 
27: bool KillRequestFilter::isKillRequest(Http::HeaderMap& headers) {
28:   // If not empty, configured kill header name will override the default header name.
29:   const Http::LowerCaseString kill_request_header_name =
30:       kill_request_.kill_request_header().empty()
31:           ? KillRequestHeaders::get().KillRequest
32:           : Http::LowerCaseString(kill_request_.kill_request_header());
33:   const auto kill_request_header = headers.get(kill_request_header_name);
34: 
35:   bool is_kill_request = false;
36:   // This is an implicitly untrusted header, so per the API documentation only
37:   // the first value is used.
38:   if (kill_request_header.empty() ||
39:       !absl::SimpleAtob(kill_request_header[0]->value().getStringView(), &is_kill_request)) {
40:     return false;
41:   }
42: 
43:   return is_kill_request;
44: }
45: 
46: Http::FilterHeadersStatus KillRequestFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
47:   bool is_correct_direction = kill_request_.direction() == KillRequest::REQUEST;
48:   const bool is_kill_request = isKillRequest(headers);
49:   if (!is_kill_request) {
50:     return Http::FilterHeadersStatus::Continue;
51:   }
52: 
53:   // Route-level configuration overrides filter-level configuration.
54:   const auto* per_route_kill_settings =
55:       Http::Utility::resolveMostSpecificPerFilterConfig<KillSettings>(decoder_callbacks_);
56: 
57:   if (per_route_kill_settings) {
58:     is_correct_direction = per_route_kill_settings->getDirection() == KillRequest::REQUEST;
59:     // Allocate the probability into kill_request in case the lifetime of
60:     // per_route_kill_settings does not match that of kill_request_
61:     kill_request_.mutable_probability()->CopyFrom(per_route_kill_settings->getProbability());
62:   }
63: 
64:   if (is_kill_request && is_correct_direction && isKillRequestEnabled()) {
65:     // Crash Envoy.
66:     RELEASE_ASSERT(false, "KillRequestFilter is crashing Envoy!!!");
67:   }
68: 
69:   return Http::FilterHeadersStatus::Continue;
70: }
71: 
72: Http::FilterHeadersStatus KillRequestFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
73:   if (kill_request_.direction() == KillRequest::REQUEST) {
74:     return Http::FilterHeadersStatus::Continue;
75:   }
76: 
77:   if (isKillRequest(headers) && isKillRequestEnabled()) {
78:     // Crash Envoy.
79:     RELEASE_ASSERT(false, "KillRequestFilter is crashing Envoy!!!");
80:   }
81: 
82:   return Http::FilterHeadersStatus::Continue;
83: }
84: 
85: } // namespace KillRequest
86: } // namespace HttpFilters
87: } // namespace Extensions
88: } // namespace Envoy
